    {
      "name": "Canyon de Chelly National Monument",
      "code": "cach",
      "description": "This canyon is home to Diné families who raise livestock, grow crops and live here. People have lived in these canyons for nearly 5,000 years, which is longer than anyone has lived continuously on the Colorado Plateau. In this place called Tsegi, their homes and images tell us their stories. Today, the park and Navajo Nation work together to manage the rich cultural and natural resources.",
      "states": [
        "AZ"
      ],
      "url": "https://www.nps.gov/cach/index.htm",
      "designation": "National Monument",
      "activities": [
        "Auto and ATV",
        "Scenic Driving",
        "Camping",
        "Guided Tours",
        "Hiking",
        "Junior Ranger Program",
        "Shopping",
        "Bookstore and Park Store"
      ],
      "weatherInfo": "Canyon de Chelly's elevation is about 5,500 feet. Spring is cool and windy; highs from 50 to 70; lows of 35 degrees. Expect dust storms and canyon flooding. Summer is hot and dry; highs from 85 to 100; lows of 51 degrees. Drink plenty of water outdoors. Fall is warm and often wet; highs from 60 to 80; lows of 40 degrees. Expect lightning, thunderstorms, and flash floods. Winter is cold and breezy; highs from 40 to 60; lows of 18 degrees. Expect 1-4 inches of snow and freezing nighttime temperatures.",
      "location": {
        "latitude": "36.14319567",
        "longitude": "-109.3388303"
      },
      "entranceFees": [],
      "operatingHours": [
        {
          "name": "Rim Drives, North and South Rim Overlooks",
          "description": "North Rim Drive, South Rim Drive, 9 overlooks open daily all year round. The Welcome Center is open daily from 8AM to 5PM and closed for Thanksgiving, Christmas, and New Years Day. Welcome Center gates open and close daily with regular business hours. No entrance fee for park.",
